/**
 * Core types for the harness orchestrator
 */

export interface Feature {
  id: string;
  category: string;
  description: string;
  steps: string[];
  passes: boolean;
  blockedBy: string | string[] | null;
  notes?: string;
}

export interface HarnessConfig {
  project: string;
  version: string;
  description: string;
  lastUpdated: string;
  goals: string[];
  features: Feature[];
  architecture?: {
    overview: string;
    components: Record<string, string>;
    dataFlow: string[];
  };
  considerations?: Record<string, string>;
}

export type TaskStatus = 'pending' | 'ready' | 'running' | 'completed' | 'failed';

export interface Task {
  feature: Feature;
  status: TaskStatus;
  startedAt?: Date;
  completedAt?: Date;
  error?: string;
  agentId?: string;
}

export interface AgentInfo {
  id: string;
  taskId: string;
  pid?: number;
  status: 'idle' | 'busy' | 'error';
  startedAt: Date;
}

export type ModelType = 'haiku' | 'sonnet' | 'opus';

export interface OrchestratorOptions {
  maxAgents: number;
  defaultModel: ModelType;
  dryRun: boolean;
  timeout: number;
  featuresPath: string;
}

export interface SchedulerResult {
  completed: string[];
  failed: string[];
  remaining: string[];
  duration: number;
}

/**
 * Harness Orchestrator
 *
 * AI Project Manager that orchestrates multiple Claude agents
 * to complete harness tasks in parallel.
 */

export * from './types.js';
export { DependencyGraph } from './graph/DependencyGraph.js';
export { CriticalPath } from './graph/CriticalPath.js';
export { TaskScheduler } from './scheduler/TaskScheduler.js';
export { PriorityQueue } from './scheduler/PriorityQueue.js';
export { AgentPool } from './agents/AgentPool.js';
export { ClaudeAgent } from './agents/ClaudeAgent.js';
export { StateManager } from './state/StateManager.js';
export { FileLock } from './state/FileLock.js';
export { AIManager } from './ai/AIManager.js';

/**
 * Dependency Graph Analyzer
 *
 * Parses features.json into a DAG and identifies:
 * - Task dependencies
 * - Parallelizable tasks
 * - Execution order (topological sort)
 */

import type { Feature, HarnessConfig } from '../types.js';

export class DependencyGraph {
  private nodes: Map<string, Feature> = new Map();
  private edges: Map<string, Set<string>> = new Map(); // nodeId -> dependents
  private reverseEdges: Map<string, Set<string>> = new Map(); // nodeId -> dependencies

  constructor(config?: HarnessConfig) {
    if (config) {
      this.build(config);
    }
  }

  /**
   * Build the dependency graph from a harness config
   */
  build(config: HarnessConfig): void {
    this.nodes.clear();
    this.edges.clear();
    this.reverseEdges.clear();

    // Add all nodes
    for (const feature of config.features) {
      this.nodes.set(feature.id, feature);
      this.edges.set(feature.id, new Set());
      this.reverseEdges.set(feature.id, new Set());
    }

    // Add edges based on blockedBy
    for (const feature of config.features) {
      const deps = this.getDependencies(feature);
      for (const dep of deps) {
        if (this.nodes.has(dep)) {
          this.edges.get(dep)!.add(feature.id);
          this.reverseEdges.get(feature.id)!.add(dep);
        }
      }
    }
  }

  /**
   * Get normalized dependencies for a feature
   */
  getDependencies(feature: Feature): string[] {
    if (!feature.blockedBy) return [];
    return Array.isArray(feature.blockedBy)
      ? feature.blockedBy
      : [feature.blockedBy];
  }

  /**
   * Get features that are ready to run (no pending dependencies)
   */
  getReadyTasks(): Feature[] {
    const ready: Feature[] = [];

    for (const [id, feature] of this.nodes) {
      if (feature.passes) continue;

      const deps = this.reverseEdges.get(id) || new Set();
      const allDepsComplete = [...deps].every(
        (depId) => this.nodes.get(depId)?.passes === true
      );

      if (allDepsComplete) {
        ready.push(feature);
      }
    }

    return ready;
  }

  /**
   * Get dependents of a task (tasks blocked by it)
   */
  getDependents(taskId: string): string[] {
    return [...(this.edges.get(taskId) || [])];
  }

  /**
   * Topological sort for execution order
   */
  topologicalSort(): string[] {
    const visited = new Set<string>();
    const result: string[] = [];

    const visit = (id: string): void => {
      if (visited.has(id)) return;
      visited.add(id);

      const deps = this.reverseEdges.get(id) || new Set();
      for (const dep of deps) {
        visit(dep);
      }

      result.push(id);
    };

    for (const id of this.nodes.keys()) {
      visit(id);
    }

    return result;
  }

  /**
   * Detect cycles in the graph (which would cause deadlock)
   */
  detectCycles(): string[] | null {
    const visited = new Set<string>();
    const stack = new Set<string>();
    const path: string[] = [];

    const dfs = (id: string): boolean => {
      visited.add(id);
      stack.add(id);
      path.push(id);

      for (const dep of this.reverseEdges.get(id) || []) {
        if (stack.has(dep)) {
          path.push(dep);
          return true;
        }
        if (!visited.has(dep) && dfs(dep)) {
          return true;
        }
      }

      stack.delete(id);
      path.pop();
      return false;
    };

    for (const id of this.nodes.keys()) {
      if (!visited.has(id) && dfs(id)) {
        return path;
      }
    }

    return null;
  }

  /**
   * Get all features
   */
  getAllFeatures(): Feature[] {
    return [...this.nodes.values()];
  }

  /**
   * Get pending features
   */
  getPendingFeatures(): Feature[] {
    return [...this.nodes.values()].filter((f) => !f.passes);
  }

  /**
   * Get a specific feature by ID
   */
  getFeature(id: string): Feature | undefined {
    return this.nodes.get(id);
  }
}

/**
 * Critical Path Calculator
 *
 * Calculates the longest path through the DAG to determine
 * minimum completion time and prioritize high-impact tasks.
 */

import type { DependencyGraph } from './DependencyGraph.js';

export interface PathInfo {
  taskId: string;
  distance: number; // Distance from start (longest path)
  onCriticalPath: boolean;
}

export class CriticalPath {
  private distances: Map<string, number> = new Map();
  private criticalPathNodes: Set<string> = new Set();

  constructor(private graph: DependencyGraph) {
    this.calculate();
  }

  /**
   * Calculate critical path distances
   */
  private calculate(): void {
    const sorted = this.graph.topologicalSort();

    // Initialize distances
    for (const id of sorted) {
      this.distances.set(id, 0);
    }

    // Forward pass: calculate longest path to each node
    for (const id of sorted) {
      const feature = this.graph.getFeature(id);
      if (!feature) continue;

      const deps = Array.isArray(feature.blockedBy)
        ? feature.blockedBy
        : feature.blockedBy
          ? [feature.blockedBy]
          : [];

      let maxDist = 0;
      for (const dep of deps) {
        const depDist = this.distances.get(dep) || 0;
        maxDist = Math.max(maxDist, depDist + 1);
      }

      this.distances.set(id, maxDist);
    }

    // Find critical path (longest path)
    let maxDistance = 0;
    let endNode = '';

    for (const [id, dist] of this.distances) {
      if (dist > maxDistance) {
        maxDistance = dist;
        endNode = id;
      }
    }

    // Backtrack to find all critical path nodes
    this.traceCriticalPath(endNode);
  }

  /**
   * Trace back the critical path from end node
   */
  private traceCriticalPath(nodeId: string): void {
    this.criticalPathNodes.add(nodeId);

    const feature = this.graph.getFeature(nodeId);
    if (!feature) return;

    const deps = Array.isArray(feature.blockedBy)
      ? feature.blockedBy
      : feature.blockedBy
        ? [feature.blockedBy]
        : [];

    const currentDist = this.distances.get(nodeId) || 0;

    for (const dep of deps) {
      const depDist = this.distances.get(dep) || 0;
      if (depDist === currentDist - 1) {
        this.traceCriticalPath(dep);
      }
    }
  }

  /**
   * Get path info for a task
   */
  getPathInfo(taskId: string): PathInfo {
    return {
      taskId,
      distance: this.distances.get(taskId) || 0,
      onCriticalPath: this.criticalPathNodes.has(taskId),
    };
  }

  /**
   * Get all tasks on the critical path
   */
  getCriticalPath(): string[] {
    const sorted = this.graph.topologicalSort();
    return sorted.filter((id) => this.criticalPathNodes.has(id));
  }

  /**
   * Get priority score for a task (higher = more important)
   */
  getPriorityScore(taskId: string): number {
    const distance = this.distances.get(taskId) || 0;
    const isCritical = this.criticalPathNodes.has(taskId) ? 100 : 0;
    const dependents = this.graph.getDependents(taskId).length * 10;

    return isCritical + dependents + (100 - distance);
  }

  /**
   * Get tasks sorted by priority
   */
  getTasksByPriority(): string[] {
    const pending = this.graph.getPendingFeatures();
    return pending
      .map((f) => ({ id: f.id, score: this.getPriorityScore(f.id) }))
      .sort((a, b) => b.score - a.score)
      .map((t) => t.id);
  }
}

/**
 * Priority Queue implementation
 *
 * Min-heap based priority queue for task scheduling.
 * Lower priority values = higher priority.
 */

interface QueueItem<T> {
  value: T;
  priority: number;
}

export class PriorityQueue<T> {
  private heap: QueueItem<T>[] = [];

  /**
   * Add an item to the queue
   */
  enqueue(value: T, priority: number): void {
    this.heap.push({ value, priority });
    this.bubbleUp(this.heap.length - 1);
  }

  /**
   * Remove and return the highest priority item
   */
  dequeue(): T | undefined {
    if (this.isEmpty()) return undefined;

    const item = this.heap[0];
    const last = this.heap.pop();

    if (this.heap.length > 0 && last) {
      this.heap[0] = last;
      this.bubbleDown(0);
    }

    return item.value;
  }

  /**
   * Peek at the highest priority item without removing
   */
  peek(): T | undefined {
    return this.heap[0]?.value;
  }

  /**
   * Check if queue is empty
   */
  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  /**
   * Get queue size
   */
  size(): number {
    return this.heap.length;
  }

  /**
   * Clear the queue
   */
  clear(): void {
    this.heap = [];
  }

  /**
   * Get all items in priority order (without removing)
   */
  toArray(): T[] {
    return [...this.heap]
      .sort((a, b) => a.priority - b.priority)
      .map((item) => item.value);
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex].priority <= this.heap[index].priority) {
        break;
      }
      this.swap(index, parentIndex);
      index = parentIndex;
    }
  }

  private bubbleDown(index: number): void {
    const length = this.heap.length;

    while (true) {
      const leftChild = 2 * index + 1;
      const rightChild = 2 * index + 2;
      let smallest = index;

      if (
        leftChild < length &&
        this.heap[leftChild].priority < this.heap[smallest].priority
      ) {
        smallest = leftChild;
      }

      if (
        rightChild < length &&
        this.heap[rightChild].priority < this.heap[smallest].priority
      ) {
        smallest = rightChild;
      }

      if (smallest === index) break;

      this.swap(index, smallest);
      index = smallest;
    }
  }

  private swap(i: number, j: number): void {
    [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
  }
}

/**
 * Task Scheduler
 *
 * Manages the ready queue and tracks in-progress tasks.
 * Determines which tasks can run next based on dependencies.
 */

import type { Feature, Task, TaskStatus } from '../types.js';
import { DependencyGraph } from '../graph/DependencyGraph.js';
import { CriticalPath } from '../graph/CriticalPath.js';
import { PriorityQueue } from './PriorityQueue.js';

export class TaskScheduler {
  private tasks: Map<string, Task> = new Map();
  private readyQueue: PriorityQueue<string> = new PriorityQueue();
  private inProgress: Set<string> = new Set();
  private criticalPath: CriticalPath;

  constructor(
    private graph: DependencyGraph,
    private maxConcurrent: number = 3
  ) {
    this.criticalPath = new CriticalPath(graph);
    this.initializeTasks();
    this.refreshReadyQueue();
  }

  private initializeTasks(): void {
    for (const feature of this.graph.getAllFeatures()) {
      this.tasks.set(feature.id, {
        feature,
        status: feature.passes ? 'completed' : 'pending',
      });
    }
  }

  /**
   * Refresh the ready queue based on current state
   */
  refreshReadyQueue(): void {
    this.readyQueue.clear();

    const ready = this.graph.getReadyTasks();
    for (const feature of ready) {
      if (
        !this.inProgress.has(feature.id) &&
        this.getTaskStatus(feature.id) === 'pending'
      ) {
        const priority = -this.criticalPath.getPriorityScore(feature.id);
        this.readyQueue.enqueue(feature.id, priority);
      }
    }
  }

  /**
   * Get the next tasks to run (up to available slots)
   */
  getNextTasks(): Feature[] {
    const available = this.maxConcurrent - this.inProgress.size;
    if (available <= 0) return [];

    const tasks: Feature[] = [];

    for (let i = 0; i < available && !this.readyQueue.isEmpty(); i++) {
      const taskId = this.readyQueue.dequeue();
      if (taskId) {
        const feature = this.graph.getFeature(taskId);
        if (feature) {
          tasks.push(feature);
          this.inProgress.add(taskId);
        }
      }
    }

    return tasks;
  }

  /**
   * Mark a task as running
   */
  startTask(taskId: string, agentId: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'running';
      task.startedAt = new Date();
      task.agentId = agentId;
      this.inProgress.add(taskId);
    }
  }

  /**
   * Mark a task as completed
   */
  completeTask(taskId: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'completed';
      task.completedAt = new Date();
      task.feature.passes = true;
      this.inProgress.delete(taskId);
      this.refreshReadyQueue();
    }
  }

  /**
   * Mark a task as failed
   */
  failTask(taskId: string, error: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'failed';
      task.error = error;
      task.completedAt = new Date();
      this.inProgress.delete(taskId);
    }
  }

  /**
   * Get task status
   */
  getTaskStatus(taskId: string): TaskStatus {
    return this.tasks.get(taskId)?.status || 'pending';
  }

  /**
   * Get task details
   */
  getTask(taskId: string): Task | undefined {
    return this.tasks.get(taskId);
  }

  /**
   * Get number of running tasks
   */
  getRunningCount(): number {
    return this.inProgress.size;
  }

  /**
   * Get all in-progress task IDs
   */
  getInProgressTasks(): string[] {
    return [...this.inProgress];
  }

  /**
   * Check if all tasks are complete
   */
  isComplete(): boolean {
    return [...this.tasks.values()].every(
      (t) => t.status === 'completed' || t.status === 'failed'
    );
  }

  /**
   * Get summary statistics
   */
  getSummary(): { pending: number; running: number; completed: number; failed: number } {
    let pending = 0,
      running = 0,
      completed = 0,
      failed = 0;

    for (const task of this.tasks.values()) {
      switch (task.status) {
        case 'pending':
        case 'ready':
          pending++;
          break;
        case 'running':
          running++;
          break;
        case 'completed':
          completed++;
          break;
        case 'failed':
          failed++;
          break;
      }
    }

    return { pending, running, completed, failed };
  }
}

/**
 * Claude Agent
 *
 * Wrapper for spawning and managing a single Claude CLI process.
 */

import { spawn, type ChildProcess } from 'node:child_process';
import { EventEmitter } from 'node:events';
import type { Feature, ModelType } from '../types.js';

export interface AgentOptions {
  model: ModelType;
  maxBudget?: number;
  timeout?: number;
  cwd?: string;
}

export interface AgentResult {
  success: boolean;
  output: string;
  error?: string;
  duration: number;
}

export class ClaudeAgent extends EventEmitter {
  readonly id: string;
  private process: ChildProcess | null = null;
  private output: string[] = [];
  private errorOutput: string[] = [];
  private startTime: number = 0;

  constructor(
    id: string,
    private options: AgentOptions
  ) {
    super();
    this.id = id;
  }

  /**
   * Execute a feature task
   */
  async executeFeature(feature: Feature): Promise<AgentResult> {
    const prompt = this.buildPrompt(feature);
    return this.execute(prompt);
  }

  /**
   * Execute a raw prompt
   */
  async execute(prompt: string): Promise<AgentResult> {
    return new Promise((resolve) => {
      this.startTime = Date.now();
      this.output = [];
      this.errorOutput = [];

      const args = this.buildArgs(prompt);

      this.process = spawn('claude', args, {
        cwd: this.options.cwd || process.cwd(),
        shell: true,
        stdio: ['inherit', 'pipe', 'pipe'],
      });

      const timeout = this.options.timeout || 10 * 60 * 1000; // 10 min default
      const timeoutId = setTimeout(() => {
        this.kill('Timeout exceeded');
      }, timeout);

      this.process.stdout?.on('data', (data: Buffer) => {
        const text = data.toString();
        this.output.push(text);
        this.emit('output', text);
      });

      this.process.stderr?.on('data', (data: Buffer) => {
        const text = data.toString();
        this.errorOutput.push(text);
        this.emit('error', text);
      });

      this.process.on('error', (err) => {
        clearTimeout(timeoutId);
        resolve({
          success: false,
          output: this.output.join(''),
          error: err.message,
          duration: Date.now() - this.startTime,
        });
      });

      this.process.on('close', (code) => {
        clearTimeout(timeoutId);
        resolve({
          success: code === 0,
          output: this.output.join(''),
          error: code !== 0 ? this.errorOutput.join('') : undefined,
          duration: Date.now() - this.startTime,
        });
      });
    });
  }

  /**
   * Build command line arguments for claude CLI
   */
  private buildArgs(prompt: string): string[] {
    const args = ['-p'];

    if (this.options.model) {
      args.push('--model', this.options.model);
    }

    if (this.options.maxBudget) {
      args.push('--max-budget-usd', String(this.options.maxBudget));
    }

    args.push(JSON.stringify(prompt));

    return args;
  }

  /**
   * Build prompt for a feature
   */
  private buildPrompt(feature: Feature): string {
    return `You are working on feature ${feature.id}: ${feature.description}

Steps to complete:
${feature.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}

${feature.notes ? `Notes: ${feature.notes}` : ''}

Important:
- Follow the harness protocol in CLAUDE.md
- Update features.json when complete (set passes: true)
- Update progress.txt with session notes
- Commit only changes for this feature
`;
  }

  /**
   * Kill the agent process
   */
  kill(reason?: string): void {
    if (this.process) {
      this.emit('killed', reason);
      this.process.kill('SIGTERM');
      this.process = null;
    }
  }

  /**
   * Check if agent is running
   */
  isRunning(): boolean {
    return this.process !== null;
  }

  /**
   * Get agent PID
   */
  getPid(): number | undefined {
    return this.process?.pid;
  }
}

/**
 * Agent Pool Manager
 *
 * Manages multiple Claude agent instances for parallel execution.
 */

import { EventEmitter } from 'node:events';
import type { Feature, ModelType, AgentInfo } from '../types.js';
import { ClaudeAgent, type AgentOptions, type AgentResult } from './ClaudeAgent.js';

export class AgentPool extends EventEmitter {
  private agents: Map<string, ClaudeAgent> = new Map();
  private agentInfo: Map<string, AgentInfo> = new Map();
  private idCounter = 0;

  constructor(
    private maxAgents: number = 3,
    private defaultOptions: Partial<AgentOptions> = {}
  ) {
    super();
  }

  /**
   * Spawn a new agent for a feature
   */
  async spawnForFeature(
    feature: Feature,
    options?: Partial<AgentOptions>
  ): Promise<AgentResult> {
    if (this.agents.size >= this.maxAgents) {
      throw new Error(`Max agents (${this.maxAgents}) reached`);
    }

    const id = `agent-${++this.idCounter}`;
    const agent = new ClaudeAgent(id, {
      model: options?.model || this.defaultOptions.model || 'sonnet',
      maxBudget: options?.maxBudget || this.defaultOptions.maxBudget,
      timeout: options?.timeout || this.defaultOptions.timeout,
      cwd: options?.cwd || this.defaultOptions.cwd,
    });

    this.agents.set(id, agent);
    this.agentInfo.set(id, {
      id,
      taskId: feature.id,
      pid: undefined,
      status: 'busy',
      startedAt: new Date(),
    });

    agent.on('output', (text) => {
      this.emit('output', { agentId: id, taskId: feature.id, text });
    });

    agent.on('error', (text) => {
      this.emit('error', { agentId: id, taskId: feature.id, text });
    });

    agent.on('killed', (reason) => {
      this.emit('killed', { agentId: id, taskId: feature.id, reason });
    });

    this.emit('spawn', { agentId: id, taskId: feature.id });

    try {
      const result = await agent.executeFeature(feature);
      this.emit('complete', { agentId: id, taskId: feature.id, result });
      return result;
    } finally {
      this.agents.delete(id);
      this.agentInfo.delete(id);
    }
  }

  /**
   * Get number of active agents
   */
  getActiveCount(): number {
    return this.agents.size;
  }

  /**
   * Get available slots
   */
  getAvailableSlots(): number {
    return this.maxAgents - this.agents.size;
  }

  /**
   * Get all agent info
   */
  getAllAgentInfo(): AgentInfo[] {
    return [...this.agentInfo.values()];
  }

  /**
   * Kill all agents
   */
  killAll(reason?: string): void {
    for (const agent of this.agents.values()) {
      agent.kill(reason);
    }
    this.agents.clear();
    this.agentInfo.clear();
  }

  /**
   * Kill a specific agent
   */
  killAgent(agentId: string, reason?: string): void {
    const agent = this.agents.get(agentId);
    if (agent) {
      agent.kill(reason);
      this.agents.delete(agentId);
      this.agentInfo.delete(agentId);
    }
  }

  /**
   * Check if pool is at capacity
   */
  isFull(): boolean {
    return this.agents.size >= this.maxAgents;
  }

  /**
   * Check if pool is empty
   */
  isEmpty(): boolean {
    return this.agents.size === 0;
  }
}

/**
 * File Lock utility
 *
 * Provides file locking to prevent race conditions
 * when multiple agents update the same file.
 */

import * as lockfile from 'proper-lockfile';
import { existsSync } from 'node:fs';

export interface LockOptions {
  stale?: number; // Time in ms before lock is considered stale
  retries?: number; // Number of retries
  realpath?: boolean; // Resolve symlinks
}

export class FileLock {
  private locks: Map<string, () => Promise<void>> = new Map();

  /**
   * Acquire a lock on a file
   */
  async acquire(filePath: string, options?: LockOptions): Promise<void> {
    if (this.locks.has(filePath)) {
      throw new Error(`Already holding lock on ${filePath}`);
    }

    if (!existsSync(filePath)) {
      throw new Error(`File does not exist: ${filePath}`);
    }

    const release = await lockfile.lock(filePath, {
      stale: options?.stale || 10000,
      retries: options?.retries || 5,
      realpath: options?.realpath ?? false,
    });

    this.locks.set(filePath, release);
  }

  /**
   * Release a lock on a file
   */
  async release(filePath: string): Promise<void> {
    const release = this.locks.get(filePath);
    if (!release) {
      throw new Error(`No lock held on ${filePath}`);
    }

    await release();
    this.locks.delete(filePath);
  }

  /**
   * Execute a function with a file lock
   */
  async withLock<T>(
    filePath: string,
    fn: () => Promise<T>,
    options?: LockOptions
  ): Promise<T> {
    await this.acquire(filePath, options);
    try {
      return await fn();
    } finally {
      await this.release(filePath);
    }
  }

  /**
   * Check if a file is locked
   */
  async isLocked(filePath: string): Promise<boolean> {
    try {
      return await lockfile.check(filePath);
    } catch {
      return false;
    }
  }

  /**
   * Release all held locks
   */
  async releaseAll(): Promise<void> {
    const releases = [...this.locks.entries()];
    for (const [path, release] of releases) {
      try {
        await release();
      } catch {
        // Ignore errors when releasing
      }
      this.locks.delete(path);
    }
  }
}

/**
 * State Manager
 *
 * Manages atomic updates to features.json and provides
 * state snapshots for recovery.
 */

import { readFileSync, writeFileSync, existsSync, copyFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import type { HarnessConfig, Feature } from '../types.js';
import { FileLock } from './FileLock.js';

export class StateManager {
  private lock: FileLock = new FileLock();
  private snapshotDir: string;

  constructor(
    private featuresPath: string,
    snapshotDir?: string
  ) {
    this.snapshotDir = snapshotDir || dirname(featuresPath);
  }

  /**
   * Load the current harness config
   */
  load(): HarnessConfig {
    const content = readFileSync(this.featuresPath, 'utf-8');
    return JSON.parse(content);
  }

  /**
   * Save the harness config atomically
   */
  async save(config: HarnessConfig): Promise<void> {
    await this.lock.withLock(this.featuresPath, async () => {
      const content = JSON.stringify(config, null, 2);
      writeFileSync(this.featuresPath, content, 'utf-8');
    });
  }

  /**
   * Update a specific feature's status
   */
  async updateFeature(
    featureId: string,
    updates: Partial<Feature>
  ): Promise<void> {
    await this.lock.withLock(this.featuresPath, async () => {
      const config = this.load();
      const feature = config.features.find((f) => f.id === featureId);

      if (!feature) {
        throw new Error(`Feature not found: ${featureId}`);
      }

      Object.assign(feature, updates);
      config.lastUpdated = new Date().toISOString().split('T')[0];

      const content = JSON.stringify(config, null, 2);
      writeFileSync(this.featuresPath, content, 'utf-8');
    });
  }

  /**
   * Mark a feature as complete
   */
  async markComplete(featureId: string): Promise<void> {
    await this.updateFeature(featureId, { passes: true });
  }

  /**
   * Create a snapshot of current state
   */
  createSnapshot(name?: string): string {
    const timestamp = Date.now();
    const snapshotName = name || `snapshot-${timestamp}`;
    const snapshotPath = join(this.snapshotDir, `${snapshotName}.json`);

    copyFileSync(this.featuresPath, snapshotPath);

    return snapshotPath;
  }

  /**
   * Restore from a snapshot
   */
  async restoreSnapshot(snapshotPath: string): Promise<void> {
    if (!existsSync(snapshotPath)) {
      throw new Error(`Snapshot not found: ${snapshotPath}`);
    }

    await this.lock.withLock(this.featuresPath, async () => {
      copyFileSync(snapshotPath, this.featuresPath);
    });
  }

  /**
   * Get progress summary
   */
  getProgress(): { total: number; completed: number; pending: number } {
    const config = this.load();
    const total = config.features.length;
    const completed = config.features.filter((f) => f.passes).length;

    return {
      total,
      completed,
      pending: total - completed,
    };
  }

  /**
   * Check if harness is complete
   */
  isComplete(): boolean {
    const config = this.load();
    return config.features.every((f) => f.passes);
  }
}

/**
 * AI Manager
 *
 * Makes intelligent decisions about task execution:
 * - Model selection based on complexity
 * - Prompt optimization
 * - Quality review
 * - Progress tracking
 */

import type { Feature, ModelType } from '../types.js';

export interface ComplexityAnalysis {
  score: number; // 1-10, higher = more complex
  factors: string[];
  recommendedModel: ModelType;
}

export class AIManager {
  /**
   * Analyze task complexity to determine optimal model
   */
  analyzeComplexity(feature: Feature): ComplexityAnalysis {
    const factors: string[] = [];
    let score = 5; // Base score

    // Step count
    if (feature.steps.length > 5) {
      score += 2;
      factors.push('Many steps');
    } else if (feature.steps.length <= 2) {
      score -= 2;
      factors.push('Few steps');
    }

    // Category-based adjustments
    if (feature.category === 'core') {
      score += 1;
      factors.push('Core component');
    } else if (feature.category === 'setup') {
      score -= 1;
      factors.push('Setup task');
    } else if (feature.category === 'intelligence') {
      score += 2;
      factors.push('AI/intelligence component');
    }

    // Notes suggest complexity
    if (feature.notes?.toLowerCase().includes('complex')) {
      score += 1;
      factors.push('Notes mention complexity');
    }
    if (feature.notes?.toLowerCase().includes('critical')) {
      score += 1;
      factors.push('Critical component');
    }

    // Clamp score
    score = Math.max(1, Math.min(10, score));

    // Model selection
    let recommendedModel: ModelType;
    if (score <= 3) {
      recommendedModel = 'haiku';
    } else if (score <= 7) {
      recommendedModel = 'sonnet';
    } else {
      recommendedModel = 'opus';
    }

    return { score, factors, recommendedModel };
  }

  /**
   * Generate optimized prompt for a feature
   */
  generatePrompt(feature: Feature, context?: string): string {
    const analysis = this.analyzeComplexity(feature);

    let prompt = `# Task: ${feature.id} - ${feature.description}

## Category
${feature.category}

## Steps
${feature.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}

`;

    if (feature.notes) {
      prompt += `## Notes
${feature.notes}

`;
    }

    if (context) {
      prompt += `## Additional Context
${context}

`;
    }

    prompt += `## Requirements
- Follow the harness protocol
- Update features.json when complete (set passes: true)
- Update progress.txt with session notes
- Commit changes for this feature only
- Test your implementation before marking complete

## Complexity Assessment
- Score: ${analysis.score}/10
- Factors: ${analysis.factors.join(', ') || 'Standard'}
`;

    return prompt;
  }

  /**
   * Review completed work quality
   */
  async reviewQuality(
    feature: Feature,
    output: string
  ): Promise<{ passed: boolean; issues: string[] }> {
    const issues: string[] = [];

    // Check for common issues in output
    if (output.toLowerCase().includes('error')) {
      issues.push('Output contains error mentions');
    }

    if (output.toLowerCase().includes('failed')) {
      issues.push('Output mentions failure');
    }

    if (!output.includes(feature.id)) {
      issues.push('Feature ID not mentioned in output');
    }

    // Check for completion signals
    const hasCompletion =
      output.includes('passes: true') ||
      output.toLowerCase().includes('completed') ||
      output.toLowerCase().includes('done');

    if (!hasCompletion) {
      issues.push('No clear completion signal');
    }

    return {
      passed: issues.length === 0,
      issues,
    };
  }

  /**
   * Suggest task reordering for efficiency
   */
  suggestReordering(features: Feature[]): string[] {
    // Simple heuristic: prioritize by complexity (easier first)
    // and by number of dependents (more dependents = higher priority)

    const analyzed = features.map((f) => ({
      id: f.id,
      complexity: this.analyzeComplexity(f).score,
      blockedBy: f.blockedBy,
    }));

    // Sort: lower complexity first, then by having fewer blockers
    analyzed.sort((a, b) => {
      const aBlockers = Array.isArray(a.blockedBy)
        ? a.blockedBy.length
        : a.blockedBy
          ? 1
          : 0;
      const bBlockers = Array.isArray(b.blockedBy)
        ? b.blockedBy.length
        : b.blockedBy
          ? 1
          : 0;

      if (aBlockers !== bBlockers) {
        return aBlockers - bBlockers;
      }
      return a.complexity - b.complexity;
    });

    return analyzed.map((a) => a.id);
  }

  /**
   * Generate progress summary
   */
  generateProgressSummary(features: Feature[]): string {
    const completed = features.filter((f) => f.passes);
    const pending = features.filter((f) => !f.passes);

    const byCategory: Record<string, { done: number; total: number }> = {};
    for (const f of features) {
      if (!byCategory[f.category]) {
        byCategory[f.category] = { done: 0, total: 0 };
      }
      byCategory[f.category].total++;
      if (f.passes) byCategory[f.category].done++;
    }

    let summary = `# Progress Summary

## Overall
- Completed: ${completed.length}/${features.length} (${Math.round((completed.length / features.length) * 100)}%)
- Pending: ${pending.length}

## By Category
`;

    for (const [cat, stats] of Object.entries(byCategory)) {
      const pct = Math.round((stats.done / stats.total) * 100);
      summary += `- ${cat}: ${stats.done}/${stats.total} (${pct}%)\n`;
    }

    if (pending.length > 0) {
      summary += `
## Next Up
`;
      for (const f of pending.slice(0, 5)) {
        summary += `- ${f.id}: ${f.description}\n`;
      }
    }

    return summary;
  }
}

#!/usr/bin/env node
/**
 * Harness Orchestrator CLI
 *
 * Command-line interface for the harness orchestrator.
 */

import { Command } from 'commander';
import chalk from 'chalk';
import ora from 'ora';
import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';

import { DependencyGraph } from '../graph/DependencyGraph.js';
import { CriticalPath } from '../graph/CriticalPath.js';
import { StateManager } from '../state/StateManager.js';
import { AIManager } from '../ai/AIManager.js';
import type { HarnessConfig } from '../types.js';

const program = new Command();

program
  .name('harness-orchestrator')
  .description('AI Project Manager for harness task orchestration')
  .version('0.1.0');

// Analyze command
program
  .command('analyze <features-path>')
  .description('Analyze dependency graph and show execution plan')
  .action((featuresPath: string) => {
    const resolvedPath = resolve(featuresPath);
    const content = readFileSync(resolvedPath, 'utf-8');
    const config: HarnessConfig = JSON.parse(content);

    const graph = new DependencyGraph(config);
    const criticalPath = new CriticalPath(graph);

    console.log(chalk.bold('\n📊 Dependency Analysis\n'));

    // Check for cycles
    const cycle = graph.detectCycles();
    if (cycle) {
      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
      process.exit(1);
    }
    console.log(chalk.green('✓ No cycles detected\n'));

    // Show features by status
    const pending = graph.getPendingFeatures();
    const completed = graph.getAllFeatures().filter((f) => f.passes);

    console.log(chalk.bold('Status:'));
    console.log(`  Completed: ${chalk.green(completed.length)}`);
    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    console.log();

    // Show ready tasks
    const ready = graph.getReadyTasks();
    console.log(chalk.bold('Ready to run (parallelizable):'));
    if (ready.length === 0) {
      console.log(chalk.dim('  None'));
    } else {
      for (const f of ready) {
        const priority = criticalPath.getPriorityScore(f.id);
        const onCritical = criticalPath.getCriticalPath().includes(f.id);
        const critical = onCritical ? chalk.red(' [CRITICAL]') : '';
        console.log(`  ${chalk.cyan(f.id)}: ${f.description}${critical} (priority: ${priority})`);
      }
    }
    console.log();

    // Show critical path
    const path = criticalPath.getCriticalPath();
    console.log(chalk.bold('Critical Path:'));
    console.log(`  ${path.map((id) => chalk.red(id)).join(' → ')}`);
    console.log();

    // Show execution order
    const order = graph.topologicalSort();
    console.log(chalk.bold('Topological Order:'));
    console.log(`  ${order.map((id) => graph.getFeature(id)?.passes ? chalk.green(id) : chalk.yellow(id)).join(' → ')}`);
  });

// Status command
program
  .command('status <features-path>')
  .description('Show current progress status')
  .action((featuresPath: string) => {
    const resolvedPath = resolve(featuresPath);
    const stateManager = new StateManager(resolvedPath);
    const aiManager = new AIManager();

    const config = stateManager.load();
    const progress = stateManager.getProgress();

    console.log(chalk.bold('\n📈 Harness Status\n'));
    console.log(`Project: ${chalk.cyan(config.project)}`);
    console.log(`Version: ${config.version}`);
    console.log(`Last Updated: ${config.lastUpdated}`);
    console.log();

    // Progress bar
    const pct = Math.round((progress.completed / progress.total) * 100);
    const filled = Math.round(pct / 5);
    const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);
    console.log(`Progress: [${bar}] ${pct}%`);
    console.log(`  ${chalk.green(progress.completed)} completed / ${chalk.yellow(progress.pending)} pending`);
    console.log();

    // Features list
    console.log(chalk.bold('Features:'));
    for (const f of config.features) {
      const status = f.passes ? chalk.green('✓') : chalk.yellow('○');
      const blockedBy = f.blockedBy
        ? chalk.dim(` (blocked by: ${Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy})`)
        : '';
      console.log(`  ${status} ${f.id}: ${f.description}${blockedBy}`);
    }

    // AI summary
    console.log('\n' + aiManager.generateProgressSummary(config.features));
  });

// Orchestrate command (placeholder - will be implemented in O006)
program
  .command('orchestrate <features-path>')
  .description('Run full orchestration with parallel agents')
  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
  .option('--dry-run', 'Show plan without executing')
  .action(async (featuresPath: string, options) => {
    const spinner = ora('Loading harness configuration...').start();

    try {
      const resolvedPath = resolve(featuresPath);
      const stateManager = new StateManager(resolvedPath);
      const config = stateManager.load();

      spinner.succeed('Configuration loaded');

      if (options.dryRun) {
        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
        console.log('Would orchestrate with:');
        console.log(`  Max agents: ${options.maxAgents}`);
        console.log(`  Model: ${options.model}`);
        console.log(`  Features: ${config.features.filter((f) => !f.passes).length} pending`);
        return;
      }

      console.log(chalk.red('\n⚠️  Full orchestration not yet implemented'));
      console.log('See feature O006 for implementation.');
      console.log('\nUse --dry-run to see the execution plan.');
    } catch (error) {
      spinner.fail('Failed to load configuration');
      console.error(error);
      process.exit(1);
    }
  });

program.parse();

